(function ($) {
    if (window.__GETIMAGE_TINYMCE_LOADED__) return;
    window.__GETIMAGE_TINYMCE_LOADED__ = true;

    tinymce.PluginManager.add('getimage', function (editor) {
        const siteHost = window.location.hostname;
        let btnControl = null;
        let isDownloading = false;

        const svgIcon = `
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 12.8 12.8">
                <path d="M11.768 7.005c.075-.28.118-.573.118-.875A3.427 3.427 0 0 0 7.09 2.987a2.741 2.741 0 0 0-5.261 1.086c0 .102.02.198.03.298A3.19 3.19 0 0 0 0 7.272a3.2 3.2 0 0 0 3.2 3.2h7.772c1.01 0 1.827-.818 1.827-1.827a1.82 1.82 0 0 0-1.032-1.64M6.4 9.1 4.115 6.815h1.373V4.53h1.827v2.285h1.373z"/>
            </svg>`;

        function getSelectedImage() {
            const node = editor.selection.getNode();
            if (!node) return null;
            if (node.nodeName === 'IMG') return node;
            return node.querySelector ? node.querySelector('img') : null;
        }

        function isInternalImage(img) {
            const src = img.getAttribute('src') || '';
            if (!src) return true;
            if (src.includes('/wp-content/uploads/')) return true;
            try {
                return new URL(src).hostname === siteHost;
            } catch (e) {
                return true;
            }
        }

        editor.addButton('getimage', {
            title: 'Download Image',
            icon: false,

            onclick: function () {
                if (isDownloading) return;

                const img = getSelectedImage();
                if (!img) {
                    alert(EXTRA_DL.i18n.no_image);
                    return;
                }

                if (isInternalImage(img)) {
                    alert(EXTRA_DL.i18n.already_local);
                    return;
                }

                const src = img.getAttribute('src');
                const postId = $('#post_ID').val();
                const alt = img.getAttribute('alt') || '';
                const title = img.getAttribute('title') || '';

                if (!src || !postId) {
                    alert(EXTRA_DL.i18n.error);
                    return;
                }

                isDownloading = true;
                editor.setProgressState(true);

                $.post(EXTRA_DL.ajax_url, {
                    action: 'getimage_image',
                    url: src,
                    post_id: postId,
                    alt: alt,
                    title: title,
                    nonce: EXTRA_DL.nonce,
                })
                .done(function (res) {
                    if (res && res.success && res.data?.new_url) {
                        const newUrl = res.data.new_url;

                        const $img = $(img);
                        const $wrapper = $img.closest('figure, picture, .fig-picture, .tplCaption');

                        if ($wrapper.length && $wrapper.find('img').length === 1) {
                            $wrapper.replaceWith(
                                `<img src="${newUrl}" alt="${alt}" title="${title}">`
                            );
                        } else {
                            $img.replaceWith(
                                `<img src="${newUrl}" alt="${alt}" title="${title}">`
                            );
                        }

                        editor.undoManager.add();
                        editor.nodeChanged();
                        alert(EXTRA_DL.i18n.success);
                    } else {
                        alert(res?.data?.message || EXTRA_DL.i18n.error);
                    }
                })
                .fail(function () {
                    alert(EXTRA_DL.i18n.connection);
                })
                .always(function () {
                    isDownloading = false;
                    editor.setProgressState(false);
                });
            },

            onPostRender: function () {
                btnControl = this;
                const el = btnControl.getEl();
                if (!el) return;

                const btn = el.querySelector('button') || el;
                btn.innerHTML = `<i class="mce-ico">${svgIcon}</i>`;
                btn.style.display = 'flex';
                btn.style.alignItems = 'center';
                btn.style.justifyContent = 'center';
                btn.style.padding = '0';
                btn.style.width = '26px';
                btn.style.height = '24px';

                const style = document.createElement('style');
                style.textContent = `
                    #${el.id} button:hover svg,
                    #${el.id}.mce-active button svg {
                        fill: var(--wp-admin-theme-color, #2271b1);
                    }
                    #${el.id}.mce-disabled button svg {
                        opacity: 0.3;
                    }
                `;
                document.head.appendChild(style);

                btnControl.disabled(true);
            }
        });

        editor.on('NodeChange', function (e) {
            if (!btnControl || !e?.element) return;

            const img =
                e.element.nodeName === 'IMG'
                    ? e.element
                    : e.element.querySelector?.('img');

            if (!img) {
                btnControl.disabled(true);
                return;
            }

            btnControl.disabled(isInternalImage(img));
        });
    });
})(jQuery);
